// Generated by the python snippet below. Do not hand-edit.
//
//   import math
//   N = 1024
//   sin_vals    = [round(math.sin(i * math.pi / 2 / N) * (1 << 30)) for i in range(N + 1)]
//   asin_vals   = [round(math.asin(i / (2 * N)) * (1 << 30)) for i in range(N + 1)]
//   atan_vals   = [round(math.atan(i / N) * (1 << 30)) for i in range(N + 1)]
//   ln_vals     = [round(math.log(1 + i / N) * (1 << 30)) for i in range(N + 1)]
//   log10_vals  = [round(math.log10(1 + i / N) * (1 << 30)) for i in range(N + 1)]
//   log2_vals   = [round(math.log2(1 + i / N) * (1 << 30)) for i in range(N + 1)]
//   exp2m1_vals = [round((2 ** (i / N) - 1) * (1 << 30)) for i in range(N + 1)]
//   ln2_q44     = round(math.log(2) * (1 << 44))
//   log10_2_q44 = round(math.log10(2) * (1 << 44))
//   # each table then appends a copy of its last entry
//
// Q30 lookup tables for the deterministic math in zc_math.cpp:
//   SIN_TABLE_Q30:    sin over [0, pi/2]      in 1024 steps (first quadrant)
//   ASIN_TABLE_Q30:   asin over [0, 0.5]      in 1024 steps (rest of the domain is
//                     reached via asin(x) = pi/2 - 2*asin(sqrt((1-x)/2)))
//   ATAN_TABLE_Q30:   atan over [0, 1]        in 1024 steps (rest of atan2's domain
//                     is reached via octant reduction)
//   LN_TABLE_Q30:     ln(1+t) over [0, 1]     in 1024 steps (mantissa part; the
//   LOG10_TABLE_Q30:  log10(1+t) over [0, 1]   exponent part is the matching Q44
//   LOG2_TABLE_Q30:   log2(1+t) over [0, 1]    constant times the binary exponent)
//   EXP2M1_TABLE_Q30: 2^t - 1 over [0, 1]     in 1024 steps
// Each table has its endpoint at [1024] plus one padding entry duplicating it,
// so interpolation may always read index + 1.
//
// The tables are checked in (rather than generated at build or run time) so
// their values cannot vary with the platform's libm: every entry is at least
// 1e-4 away from a rounding boundary, but checking in the result removes all
// doubt.

